import streamlit as stimport osimport sysfrom config import APP_TITLE, APP_ICONst.set_page_config(page_title=APP_TITLE, page_icon=APP_ICON,                   layout="wide", initial_sidebar_state="expanded")# ========== DÉBUT DEBUG ==========print("=== DEBUG START ===", flush=True)try:    import config    print("config OK", flush=True)    import utils.data_utils as du    print("data_utils OK", flush=True)    df_test = du.load_dataset(sample_size=10)    print(f"Connexion OK, {len(df_test)} lignes chargées", flush=True)except Exception as e:    print(f"ERREUR IMPORT/CONNEXION: {e}", flush=True)    import traceback    traceback.print_exc()    sys.exit(1)print("=== DEBUG END ===", flush=True)# ========== ROUTING DEBUG ==========print("=== ROUTING DEBUG START ===", flush=True)try:    from views.dashboard import render as dashboard_render    print("dashboard import OK", flush=True)    from views.eda import render as eda_render    print("eda import OK", flush=True)    from views.prediction import render as prediction_render    print("prediction import OK", flush=True)    from views.prioritisation import render as prioritisation_render    print("prioritisation import OK", flush=True)    from views.chatbot import render as chatbot_render    print("chatbot import OK", flush=True)except Exception as e:    print(f"ERREUR IMPORT VUE: {e}", flush=True)    import traceback    traceback.print_exc()    sys.exit(1)print("=== ROUTING DEBUG END ===", flush=True)# ========== CSS ==========css_path = os.path.join(os.path.dirname(__file__), "assets", "style.css")if os.path.exists(css_path):    with open(css_path) as f:        st.markdown(f"<style>{f.read()}</style>", unsafe_allow_html=True)# ========== SIDEBAR ==========with st.sidebar:    st.markdown("""    <div style='text-align:center;padding:16px 0 24px 0;'>        <div style='font-size:2.5rem;'>✈️</div>        <div style='font-size:1.1rem;font-weight:700;color:#E94560;letter-spacing:0.05em;'>IMSD 25-26</div>        <div style='font-size:0.75rem;color:#6B7280;text-transform:uppercase;letter-spacing:0.1em;'>Flight Risk Intelligence</div>    </div>    <hr style='border-color:#1F2937;margin:0 0 16px 0;'>    """, unsafe_allow_html=True)    page = st.radio("Navigation", options=[        "🏠  Dashboard","📊  Analyse Exploratoire",        "🎯  Prédiction","🚨  Priorisation CRM","💬  Assistant IA",    ], label_visibility="collapsed")    st.markdown("""    <hr style='border-color:#1F2937;margin:16px 0;'>    <div style='font-size:0.72rem;color:#6B7280;text-align:center;'>        v1.0.0 · IMSD 25-26 · SQLite<br>        <span style='color:#2ECC71;'>● Modèle actif</span>    </div>    """, unsafe_allow_html=True)# ========== ROUTING ==========pages = {    "🏠  Dashboard": "dashboard",    "📊  Analyse Exploratoire": "eda",    "🎯  Prédiction": "prediction",    "🚨  Priorisation CRM": "prioritisation",    "💬  Assistant IA": "chatbot"}selected = pages.get(page)print(f"Page sélectionnée: {selected}", flush=True)try:    if selected == "dashboard":        dashboard_render()    elif selected == "eda":        eda_render()    elif selected == "prediction":        prediction_render()    elif selected == "prioritisation":        prioritisation_render()    elif selected == "chatbot":        chatbot_render()except Exception as e:    print(f"ERREUR DANS RENDER: {e}", flush=True)    import traceback    traceback.print_exc()    st.error(f"Erreur lors de l'affichage de la page: {e}")